import React, { useState } from 'react';
import GalleryModal from './GalleryModal';

const CommunityGalleryImage = props => {
  const [modalShow, setModalShow] = useState(false);
  const { image } = props;

  return (
    <div
      className="image-item"
      style={{ paddingBottom: '35px', border: '10px solid black' }}
      key={'image-' + image.number}
    >
      <img
        className="img-fluid"
        src={image.image}
        alt={'image' + image.number}
        onClick={() => setModalShow(true)}
      />
      <p
        style={{
          fontSize: '15px',
          marginRight: '16px',
          marginTop: '10px',
        }}
      >
        #{image.title}
      </p>
      <GalleryModal
        image={image}
        show={modalShow}
        onHide={() => setModalShow(false)}
      />
    </div>
  );
};

export default CommunityGalleryImage;
